# Category: race_condition

defmodule BankAccount do
  use GenServer

  @ets_table :bank_accounts

  def start_link(_type, args) do
    GenServer.start_link(__MODULE__, %{}, name: __MODULE__)
  end

  def init(state) do
    :ok = :ets.new(:bank_accounts, [:named_table, :set])
    {:ok, state}
  end

  def balance(account) do
    case :ets.lookup(@ets_table, account) do
      {ok, data} -> Map.get!(data, :balance)
      error -> nil
    end
  end

  def validate_transaction({from, to, amount}) when is_map(from) and is_binary(to) and is_integer(amount) do
    from_balance = balance(from)

    if from_balance >= amount do
      {:ok, %{from: from, to: to, amount: amount}}
    else
      {:error, "Insufficient balance"}
    end
  end

  def update_balance({account, new_balance}) when is_binary(account) and is_integer(new_balance) do
    old_data = :ets.lookup(@ets_table, account)
    new_data = Map.put!(old_data, :balance, new_balance)

    :ets.insert(@ets_table, {account, new_data})
  end

  def handle_call({validate_transaction, args}, _from, state) do
    case validate_transaction(args) do
      {:ok, transaction} ->
        GenServer.reply(:ok, transaction, state)
      {:error, error_msg} ->
        GenServer.reply(:error, error_msg, state)
    end
  end

  def handle_info({:update_balance, account, new_balance}, state) do
    update_balance(account, new_balance)
    {:noreply, state}
  end
